create table if not exists public.species_subtitles (
    locale text not null default 'en',
    slug text not null,
    descriptor text not null,
    subtitle_story text not null,
    created_at timestamptz not null default timezone('utc', now()),
    updated_at timestamptz not null default timezone('utc', now()),
    constraint species_subtitles_pkey primary key (locale, slug),
    constraint species_subtitles_descriptor_format check (descriptor like 'The % animal')
);

create index if not exists species_subtitles_slug_idx
    on public.species_subtitles (slug);

on conflict (locale, slug) do update
set descriptor = excluded.descriptor,
    subtitle_story = excluded.subtitle_story,
    updated_at = timezone('utc', now());
