insert into public.species_subtitles (locale, slug, descriptor, subtitle_story)
values
    ('en', 'african-wild-dog', 'The fast pack signal hunter animal', 'The African Wild Dog is a fast hunter with big ears and a coat covered in splashy colors. It works with its pack like a team, so everyone helps chase, turn, and catch.'),
    ('en', 'american-alligator', 'The swamp-edge patience force animal', 'The American Alligator is a heavy reptile that waits in warm swamps and rivers with patient eyes. At the edge of the water, waiting is one of its strongest tricks.'),
    ('en', 'american-bullfrog', 'The booming pond-claim king animal', 'The American Bullfrog is a large pond frog with a deep booming call. Its loud voice helps it claim space and tell other frogs, ''This pond is mine.'''),
    ('en', 'atlantic-puffin', 'The master of three realms animal', 'The Atlantic Puffin is a funny seabird with a bright beak and wings that work in air and underwater. It can fly in the sky, walk on land, and paddle through the sea like it belongs in all three places.'),
    ('en', 'atlas-moth', 'The giant final-message animal', 'The Atlas Moth is a giant moth with huge wings and a short adult life. It spends most of its time preparing for one brief beautiful moment to fly, mate, and pass life on.'),
    ('en', 'axolotl', 'The smiling regeneration mystery animal', 'The Axolotl is a smiling water animal with feathery gills sticking out from its head. It is amazing because it can grow back lost body parts, almost like a little healing magician.'),
    ('en', 'babirusa', 'The strange-tusk island rooter animal', 'The Babirusa is a wild pig from islands in Indonesia, famous for its strange curling tusks. It may look odd, but it helps stir and feed the forest in quiet ways.'),
    ('en', 'bald-eagle', 'The high water-reading ruler animal', 'The Bald Eagle is a giant bird with a white head and sharp eyes that can spot food from far away. It teaches that seeing the whole picture first can make the next move easier.'),
    ('en', 'bali-myna', 'The rare white song jewel animal', 'The Bali Myna is a rare white bird with a soft crest and bright blue skin around its eyes. It reminds us that beautiful living things need protection when there are only a few left.'),
    ('en', 'barn-owl', 'The silent dark-listening hunter animal', 'The Barn Owl is a pale night bird with a heart-shaped face that helps it hear tiny sounds in the dark. It flies so quietly that mice often do not know it is coming.'),
    ('en', 'barn-swallow', 'The swift barn-sky sweeper animal', 'The Barn Swallow is a quick little bird that zips through the sky catching insects while it flies. It turns the air above fields and farms into its moving dinner table.'),
    ('en', 'binturong', 'The shaggy canopy seed carrier animal', 'The Binturong is a shaggy tree animal with a tail that can help it hold onto branches. As it eats fruit and travels, it helps spread seeds so new forest can grow.'),
    ('en', 'black-mamba', 'The lightning-fast warning serpent animal', 'The Black Mamba is a very fast snake with quick movement and a strong warning display. It likes clear direct action and does not waste time when danger comes close.'),
    ('en', 'bluefin-tuna', 'The endless blue sprint animal', 'The Bluefin Tuna is a strong sleek fish built for long fast swims across the open ocean. It keeps going for huge distances, proving that stamina can be just as important as speed.'),
    ('en', 'capybara', 'The calm riverside peace-holder animal', 'The Capybara is the biggest rodent in the world and loves to sit near rivers and ponds. It stays calm because it knows water is close if it needs a quick escape.'),
    ('en', 'chambered-nautilus', 'The spiral depth-tuning elder animal', 'The Nautilus is a sea creature with a beautiful curly shell that works like a little submarine. Inside its shell are tiny rooms that help it float up high or sink down deep, and it moves slowly through reef water looking for food.'),
    ('en', 'chameleon', 'The still color-shifting watcher animal', 'The Chameleon is a slow climbing lizard with eyes that can look in different directions. It likes to stay still, blend in, and shoot out its tongue when the bug is close enough.'),
    ('en', 'cheetah', 'The pure burst-speed arrow animal', 'The Cheetah is the fastest land animal and can burst across the grass like a striped arrow. Because speed takes a lot of energy, it saves its fastest run for the right moment.'),
    ('en', 'chinese-giant-salamander', 'The ancient river-bottom giant animal', 'The Chinese Giant Salamander is one of the biggest amphibians on Earth and lives in cool streams. It is an ancient animal that seems to carry very old river secrets with it.'),
    ('en', 'cicada', 'The underground time-bomb singer animal', 'The Cicada lives underground for years and then comes out all at once to sing loudly in the trees. It shows that timing can be a powerful kind of magic.'),
    ('en', 'clownfish', 'The anemone-house alliance animal', 'The Clownfish lives among the waving arms of a sea anemone without getting stung. Because it understands that prickly home, danger becomes shelter.'),
    ('en', 'common-kingfisher', 'The blue lightning river-dart animal', 'The Kingfisher is a small blue-and-orange bird that watches water carefully from a branch. Then it shoots down like a spark to catch a fish.'),
    ('en', 'crocodile', 'The patient bottleneck ambush ruler animal', 'The Crocodile is a huge reptile that waits in rivers and swamps with only its eyes above the water. It shows how being patient in the right place can be stronger than rushing everywhere.'),
    ('en', 'crow', 'The clever urban puzzle solver animal', 'The Crow is a clever black bird that remembers faces and solves little problems like puzzles. It shows that a smart mind can turn almost anything into a useful tool.'),
    ('en', 'cuttlefish', 'The living color-screen illusion animal', 'The Cuttlefish is a smart sea animal that can change the color and pattern of its skin in a flash. It uses its body like a living screen to hide, hunt, or send a message.'),
    ('en', 'dolphin', 'The echo-guided pod genius animal', 'The Dolphin is a playful sea mammal that uses clicks and echoes to find its way and hunt fish. It can listen to the water like a map even when it cannot see clearly.'),
    ('en', 'dragonfly', 'The ancient air-target ace animal', 'The Dragonfly is a shining flying hunter that can zip, stop, and turn in the air with amazing control. It moves like it already knows exactly where it wants to go.'),
    ('en', 'dung-beetle', 'The rolling waste-to-gold animal', 'The Dung Beetle is a little bug that rolls animal poop into a ball and carries it away. It may seem messy, but this hard work helps clean the land and feed the soil.'),
    ('en', 'eagle', 'The high thermal vision king animal', 'The Eagle is a strong bird with wide wings and eyes built for looking far below. It likes to rise high, choose the best moment, and swoop down when it is ready.'),
    ('en', 'elephant', 'The heavy ancestral memory keeper animal', 'The Elephant is a giant animal with a long trunk, huge feet, and a very good memory. It remembers safe paths, water places, and family voices, almost like it carries an old map inside its head.'),
    ('en', 'emperor-penguin', 'The winter huddle endurance animal', 'The Emperor Penguin is a tall penguin that lives in the freezing Antarctic cold. When the wind gets fierce, penguins huddle close and share warmth like a living blanket.'),
    ('en', 'fennec-fox', 'The big-eared desert listener animal', 'The Fennec Fox is a tiny desert fox with giant ears that help it hear and stay cool. In a hot hard place, good listening can be even better than big muscles.'),
    ('en', 'firefly', 'The tiny light-code signal animal', 'The Firefly is a tiny bug that makes its own light blink in the dark. It shows that even a very small light can still help others find the way.'),
    ('en', 'frilled-lizard', 'The sudden fear-flare runner animal', 'The Frilled Lizard is a little reptile with a big neck frill that pops open like a surprise umbrella. When it feels scared, that sudden flash can make an enemy think twice.'),
    ('en', 'giant-panda', 'The peaceful bamboo strength animal', 'The Giant Panda is a big black-and-white bear that spends much of its time eating bamboo. It shows that a peaceful simple life can still be strong and special.'),
    ('en', 'giraffe', 'The tall far-seeing grazer animal', 'The Giraffe is the tallest land animal, with a long neck that reaches leaves high in the trees. Its great height lets it see farther and find food other animals cannot reach.'),
    ('en', 'glass-frog', 'The transparent leaf-shadow spirit animal', 'The Glass Frog is a small green frog with skin so clear that you can sometimes see inside its body. It hides well on leaves because it looks light, delicate, and hard to notice.'),
    ('en', 'great-blue-heron', 'The still-water spear master animal', 'The Great Blue Heron is a tall blue-gray bird that stands very still beside water. It waits patiently until the perfect second and then grabs a fish with its sharp beak.'),
    ('en', 'great-white-shark', 'The sharp-sensed apex torpedo animal', 'The Great White Shark is a strong fast hunter with sharp senses that can notice movement, smell, and electrical signals in the water. Its power comes from many parts working together, not from teeth alone.'),
    ('en', 'greater-bird-of-paradise', 'The dazzling dance-display spirit animal', 'The Greater Bird-of-paradise is famous for its shining feathers and dancing displays in the trees. It shows that sometimes movement and beauty are part of the message.'),
    ('en', 'greater-flamingo', 'The pink salt-water filter animal', 'The Greater Flamingo is a tall pink bird that sweeps tiny food from shallow salty water. It shows that lots of little things can build something big and bright.'),
    ('en', 'green-anaconda', 'The river-thick constricting titan animal', 'The Green Anaconda is a giant snake that lives in rivers and wetlands in South America. The water helps carry its heavy body, making its huge size easier to use.'),
    ('en', 'green-sea-turtle', 'The ancient ocean garden-keeper animal', 'The Green Sea Turtle is a gentle ocean traveler that eats seagrass in shallow water. By trimming those underwater meadows, it helps keep them healthy and growing.'),
    ('en', 'hellbender', 'The flat-rock river keeper animal', 'The Hellbender is a big flat salamander that hides under rocks in cold clean streams. When a river stays healthy and clear, quiet animals like this can keep living there.'),
    ('en', 'honey-bee', 'The sacred flower-routing hive animal', 'The Honey Bee is a fuzzy little worker that gathers nectar and pollen from flowers. When it finds something good, it goes home and tells the hive where to go.'),
    ('en', 'hoopoe', 'The crowned ground-probing oracle animal', 'The Hoopoe is a bird with a crown of feathers and a long beak for poking into the ground. It finds hidden bugs by looking where other animals forget to search.'),
    ('en', 'indian-peafowl', 'The radiant display signal animal', 'The Indian Peafowl is a bright bird with a giant fan of shining tail feathers. Its beautiful display is a way of talking without words and saying, ''Look at me.'''),
    ('en', 'jellyfish', 'The drifting soft-sting pulse animal', 'The Jellyfish is a soft drifting sea animal with stinging arms. It lets the water carry it, showing that sometimes moving with the flow is the smartest choice.'),
    ('en', 'jumping-spider', 'The tiny precision leap hunter animal', 'The Jumping Spider is a tiny hunter with big eyes and a brave jump. It does not need to be large because it aims carefully and leaps at just the right moment.'),
    ('en', 'king-cobra', 'The tall venom sovereign serpent animal', 'The King Cobra is a long powerful snake that eats other snakes and can lift the front of its body high off the ground. It shows that being really good at one hard thing can be a special kind of power.'),
    ('en', 'koala', 'The sleepy eucalyptus dream animal', 'The Koala is a fluffy tree animal that spends much of the day sleeping and eating eucalyptus leaves. It lives slowly because its food gives it only a little energy.'),
    ('en', 'komodo-dragon', 'The patient island apex force animal', 'The Komodo Dragon is a giant lizard from hot islands in Indonesia. It likes to wait, watch, and use its big strength only when the moment is right.'),
    ('en', 'laughing-kookaburra', 'The laughing branch-top ambusher animal', 'The Laughing Kookaburra is a chunky bird with a call that sounds like loud happy laughter. Even with that silly voice, it is a sharp hunter that watches carefully from a branch.'),
    ('en', 'leafcutter-ant', 'The farming fungus empire animal', 'The Leafcutter Ant carries pieces of leaves into underground rooms, but not to eat them right away. It grows fungus like a tiny farmer, making its own food garden below the ground.'),
    ('en', 'leopard', 'The quiet everywhere survivor animal', 'The Leopard is a spotted big cat that can climb, hide, and hunt in many different places. It stays alive by being quiet, flexible, and ready for almost anything.'),
    ('en', 'leopard-gecko', 'The spotted twilight hide-master animal', 'The Leopard Gecko is a small spotted lizard with bright eyes and a gentle way of moving. It survives by hiding well, coming out at the right time, and not wasting energy.'),
    ('en', 'lion', 'The calm solar pride ruler animal', 'The Lion is a powerful big cat that lives with a pride on open land. It does not need to fight all the time because real strength knows when to rest and when to act.'),
    ('en', 'lionfish', 'The beautiful venom invasion animal', 'The Lionfish is a beautiful striped fish with long spiky fins and venomous points for protection. In the wrong reef it can spread too fast, showing that even pretty things can cause big trouble.'),
    ('en', 'maine-coon-cat', 'The gentle winter giant animal', 'The Maine Coon is a huge fluffy cat with tufted ears and a long bushy tail. It is built for cold weather and feels like a soft blanket with paws.'),
    ('en', 'malayan-tapir', 'The moonlit forest path-maker animal', 'The Malayan Tapir is a shy forest animal with a black-and-white body and a little trunk-like nose. It moves quietly at night, eating plants and carrying seeds through the jungle.'),
    ('en', 'manta-ray', 'The flying filter-wing ocean animal', 'The Manta Ray is a huge flat sea animal that glides through water like a bird in the sky. It opens its mouth as it swims to filter tiny food from the sea.'),
    ('en', 'mantis-shrimp', 'The rainbow hammer strike animal', 'The Mantis Shrimp is a bright sea hunter with amazing eyes and a punch faster than you can see. It keeps its power ready inside like a spring and then lets it snap.'),
    ('en', 'marine-iguana', 'The sea-grazing lava lizard animal', 'The Marine Iguana is a lizard from the Galapagos that swims into the sea to eat algae from rocks. It is special because it learned to live where most lizards never go.'),
    ('en', 'meerkat', 'The upright shared-watch scout animal', 'The Meerkat is a small desert animal that likes to stand up tall and look around. One meerkat watches while the others dig or eat, so the whole group stays safer.'),
    ('en', 'monarch-butterfly', 'The royal migration map animal', 'The Monarch Butterfly is a bright orange butterfly that travels huge distances on delicate wings. It shows that even something small can carry a giant journey inside it.'),
    ('en', 'octopus', 'The fluid escape artist thinker animal', 'The Octopus is a smart sea animal with eight arms and a squishy body that can squeeze through tiny spaces. When a problem appears, it can change color, change shape, and think of a new escape.'),
    ('en', 'orangutan', 'The slow wise canopy builder animal', 'The Orangutan is a long-armed forest ape that swings, climbs, and makes careful choices in the trees. It learns slowly and deeply, like it is studying the jungle one branch at a time.'),
    ('en', 'orchid-mantis', 'The flower-disguised trap artist animal', 'The Orchid Mantis looks so much like a flower that other insects can be fooled by it. What seems beautiful and harmless can sometimes be a very clever trap.'),
    ('en', 'peregrine-falcon', 'The falling sky-bullet hunter animal', 'The Peregrine Falcon is one of the fastest animals on Earth and dives through the sky like a living dart. It lets gravity help it, so the fall becomes part of the power.'),
    ('en', 'plains-zebra', 'The striped confusion shield animal', 'The Plains Zebra is a horse-like animal covered in black-and-white stripes. When zebras move together, their stripes can blur into one wiggly pattern that confuses danger.'),
    ('en', 'poison-dart-frog', 'The bright warning drop animal', 'The Poison Dart Frog is tiny and brightly colored, like a living warning sign. Its colors tell other animals, ''Do not touch me.'''),
    ('en', 'polar-bear', 'The ice-platform endurance hunter animal', 'The Polar Bear is a giant white bear that hunts on sea ice in the Arctic. It depends on that icy floor, so when the ice changes, its whole hunting life changes too.'),
    ('en', 'praying-mantis', 'The prayer-armed patience blade animal', 'The Praying Mantis is a bug with folded arms that make it look peaceful and thoughtful. But when food comes close, it strikes with lightning-fast timing.'),
    ('en', 'proboscis-monkey', 'The river-corridor leaf sage animal', 'The Proboscis Monkey is a funny-looking monkey with a big nose and a love for river forests. It swims well and moves along the watery edges where trees and rivers meet.'),
    ('en', 'rainbow-bee-eater', 'The rainbow aerial insect-catcher animal', 'The Rainbow Bee-eater is a bright little bird that catches flying insects in midair. It is beautiful to look at, but it is also a fast and skilled hunter.'),
    ('en', 'red-eyed-tree-frog', 'The red-eyed surprise shield animal', 'The Red-eyed Tree Frog is a bright green frog with giant red eyes and sticky feet for climbing. When surprised, it flashes those bold eyes and colors to buy a second to escape.'),
    ('en', 'red-fox', 'The adaptable trickster edge-walker animal', 'The Red Fox is a bright orange hunter with sharp ears and quick feet. It changes its tricks to fit the place, which helps it live in forests, fields, and even near towns.'),
    ('en', 'red-kangaroo', 'The red desert spring-force animal', 'The Red Kangaroo is a huge jumper from the dry lands of Australia. Its strong legs and tail help it cross big open places without wasting too much energy.'),
    ('en', 'red-panda', 'The gentle cool-canopy browser animal', 'The Red Panda is a fluffy red tree animal with a striped tail and gentle face. It needs cool forests where the branches connect, like a wooden road through the mountains.'),
    ('en', 'reticulated-python', 'The patterned crushing rope animal', 'The Reticulated Python is a very long snake with a beautiful net-like pattern on its skin. It does not chase fast with claws or teeth, but wraps its body around prey with quiet power.'),
    ('en', 'rhinoceros-beetle', 'The horned lifting warrior animal', 'The Rhinoceros Beetle is a heavy shiny bug with a horn like a tiny lifting machine. Its body shape helps it push and hoist much better than you would expect.'),
    ('en', 'rhinoceros-hornbill', 'The thunder-beaked canopy courier animal', 'The Rhinoceros Hornbill is a big forest bird with a huge curved beak and a helmet-like bump on top. Its loud calls help family members stay connected across the tall trees.'),
    ('en', 'ring-tailed-lemur', 'The scented social sunbather animal', 'The Ring-tailed Lemur is a monkey-like animal with a long striped tail and a very social life. It uses smells, sounds, and body signs to keep its family together.'),
    ('en', 'ruby-throated-hummingbird', 'The hovering nectar jewel animal', 'The Ruby-throated Hummingbird is a tiny bird that can hover in front of flowers and sip nectar with a long tongue. It moves fast, but every little wingbeat is carefully controlled.'),
    ('en', 'scalloped-hammerhead', 'The wide-headed signal scanner animal', 'The Scalloped Hammerhead is a shark with a wide hammer-shaped head that helps it sense more of the world around it. Seeing and feeling more clearly helps it make smarter hunting moves.'),
    ('en', 'scarlet-macaw', 'The loud rainbow seed-scatterer animal', 'The Scarlet Macaw is a loud red, yellow, and blue parrot that flies through the rainforest in bright flashes of color. It spreads seeds as it eats fruit, almost like joy with wings.'),
    ('en', 'sea-cucumber', 'The soft seafloor recycler animal', 'The Sea Cucumber is a soft slow sea animal that crawls along the ocean floor eating bits of mess from the sand. It helps clean the seabed so the underwater world keeps working well.'),
    ('en', 'seahorse', 'The upright tidal anchor animal', 'The Seahorse is a tiny fish that swims upright and curls its tail around plants to stay steady. Holding on helps it stay calm while the water moves all around it.'),
    ('en', 'secretary-bird', 'The long-legged snake-stomper animal', 'The Secretarybird is a tall bird that hunts on the ground with long strong legs. Instead of fighting snakes where they are strongest, it uses its fast feet to stay in control.'),
    ('en', 'shoebill', 'The prehistoric swamp stillness animal', 'The Shoebill is a huge swamp bird with a giant beak that looks almost prehistoric. It can stand still for a very long time, waiting for the right moment to strike.'),
    ('en', 'snow-leopard', 'The hidden mountain ghost power animal', 'The Snow Leopard is a pale spotted cat that blends into rocky mountains like a ghost. It stays hidden so well that the cold cliffs almost seem to wear it like a coat.'),
    ('en', 'southern-cassowary', 'The armored rainforest seed-giant animal', 'The Southern Cassowary is a giant rainforest bird with strong legs and a bright blue neck. It eats fruit and drops seeds far away, helping new trees grow across the forest.'),
    ('en', 'spotted-hyena', 'The laughing bone-crushing recycler animal', 'The Hyena is a strong spotted hunter with a laugh-like call and very powerful jaws. It uses almost every bit of food it finds, so little goes to waste.'),
    ('en', 'sun-bear', 'The small forest treasure-opener animal', 'The Sun Bear is the smallest bear, with a long tongue and strong claws for reaching hidden food. It is good at opening logs, nests, and tough places where tasty things are hiding.'),
    ('en', 'sunda-pangolin', 'The armored ant-eating drill animal', 'The Sunda Pangolin is covered in hard scales and curls into a ball when it feels scared. It uses long claws and a sticky tongue to break into ant and termite homes for dinner.'),
    ('en', 'termite', 'The hidden earth-factory builder animal', 'The Termite is a small bug that eats dead wood and lives in giant busy colonies. Tiny workers like these help turn old things into new soil and keep the ground alive.'),
    ('en', 'three-toed-sloth', 'The slow invisible energy-saver animal', 'The Three-toed Sloth hangs upside down in the trees and moves so slowly that it almost looks like part of the branch. By being gentle and quiet, it is harder for enemies to notice.'),
    ('en', 'tiger', 'The silent striped force animal', 'The Tiger is a striped big cat that moves quietly through grass and forest before it hunts. It shows that calm focus can be stronger than making a lot of noise.'),
    ('en', 'toco-toucan', 'The giant-beaked fruit courier animal', 'The Toco Toucan is a colorful bird with a giant beak that helps it reach and carry fruit. As it moves around eating, it spreads seeds like a flying fruit helper.'),
    ('en', 'wallaces-flying-frog', 'The gliding jungle parachute animal', 'Wallace''s Flying Frog is a tree frog with wide webbed feet that help it glide through the air. It does not really fly like a bird, but it can turn a fall into a smooth little sail.'),
    ('en', 'wandering-albatross', 'The endless wind-riding sailor animal', 'The Wandering Albatross is a giant seabird with enormous wings that ride ocean winds for days. It shows that long journeys get easier when you let the air help carry you.'),
    ('en', 'whale-shark', 'The gentle ocean giant filter animal', 'The Whale Shark is the biggest fish in the ocean, but it mostly eats tiny food floating in the water. It proves that something huge can still move gently and peacefully.'),
    ('en', 'white-headed-vulture', 'The clean-sky carrion judge animal', 'The White-headed Vulture is a big bird that flies high and looks for animals that have already died. It helps clean the land so sickness does not spread and the wild stays healthier.'),
    ('en', 'wolf', 'The wild pack frequency leader animal', 'The Wolf is a wild dog that hunts, travels, and cares for its family as a pack. It shows that sharing a path and helping each other makes a group stronger.'),
    ('en', 'wolverine', 'The relentless cold-range survivor animal', 'The Wolverine is a tough furry hunter that can cross snow, ice, and lonely cold places. It keeps going when the land is harsh, showing that grit can be a kind of superpower.')
